// cd10b — Preparer Prompt Directives
const allItems = $('Charger Slots a Couvrir').all();
const slots = allItems.filter(item => !item.json._noSlots);

if (slots.length === 0) {
  return [{ json: { _skip: true, slotsData: [], slotsCount: 0 } }];
}

const slotsForPrompt = slots.map((p, i) => {
  const s = p.json;
  return {
    index: i,
    theme: s.theme || '',
    category: s.category || 'produit',
    visual_direction: s.visual_direction || '',
    content_type: s.content_type || 'post',
    angle: s.angle || '',
    compositing_context: s.compositing_context || null
  };
});

const clientName = slots[0].json.client_name || 'Client';

const prompt = `Tu es un directeur artistique specialise dans le contenu Instagram pour des marques.

<task>
Le client "${clientName}" possede une banque de photos existantes. Pour chaque creneau editorial ci-dessous, genere des directives precises pour aider l'operateur a SELECTIONNER les bonnes photos dans cette banque.
</task>

<slots>
${JSON.stringify(slotsForPrompt, null, 2)}
</slots>

<rules>
- Pour chaque slot, decris quel TYPE de photo sujet chercher dans la banque (ex: "burger classique vu de dessus", "photo equipe en cuisine souriant", "salade fraiche coloree")
- Si compositing_context est rempli : decrire AUSSI quel type de photo contexte (decor/ambiance) chercher (ex: "terrasse ensoleillee", "comptoir bois rustique", "fond restaurant chaleureux"). Preciser que 2 PHOTOS SEPAREES sont necessaires.
- Si compositing_context est null : une seule photo sujet suffit, le decor peut y etre inclus
- 2-3 bullet points par type de photo, courts et concrets
- Oriente "que chercher dans la banque", pas "comment photographier"
- Pas de jargon technique
</rules>

<output_format>
JSON valide :
{
  "directives": [
    {
      "index": 0,
      "photo_sujet": "- Description 1\\n- Description 2",
      "photo_contexte": "- Description contexte 1\\n- Description 2"
    }
  ]
}
photo_contexte doit etre null si compositing_context est null/vide.
</output_format>`;

// Merger drive_folder_url depuis staticData (rempli dans cd10)
const staticData = $getWorkflowStaticData('global');
const processed = staticData.processedSlots || [];
const slotsWithUrls = slots.map(p => {
  const s = p.json;
  const proc = processed.find(ps => ps.id === s.id);
  return { ...s, drive_folder_url: proc ? proc.drive_folder_url : null };
});

return [{ json: {
  prompt,
  slotsData: slotsWithUrls,
  slotsCount: slotsWithUrls.length
}}];
